// threadPost is one node in a reconstructed conversation, projected from a
// synced tweet's high-gravity fields plus a computed reply depth.
type threadPost struct {
	ID             string `json:"id"`
	AuthorID       string `json:"author_id,omitempty"`
	Text           string `json:"text,omitempty"`
	CreatedAt      string `json:"created_at,omitempty"`
	ConversationID string `json:"conversation_id,omitempty"`
	InReplyTo      string `json:"in_reply_to,omitempty"`
	Depth          int    `json:"depth"`
}

// syncedTweet mirrors the X v2 post fields thread reconstruction needs. Reads
// from the locally synced JSON, so it only sees fields a prior sync requested
// (request tweet.fields=conversation_id,referenced_tweets,created_at to populate
// the reply graph).
type syncedTweet struct {
	ID               string `json:"id"`
	Text             string `json:"text"`
	AuthorID         string `json:"author_id"`
	CreatedAt        string `json:"created_at"`
	ConversationID   string `json:"conversation_id"`
	ReferencedTweets []struct {
		Type string `json:"type"`
		ID   string `json:"id"`
	} `json:"referenced_tweets"`
}

// repliedToParent returns the id of the post this one replies to, or "" when it
// is a root, quote, or repost rather than a reply.
func (t syncedTweet) repliedToParent() string {
	for _, ref := range t.ReferencedTweets {
		if ref.Type == "replied_to" {
			return ref.ID
		}
	}
	return ""
}

